export const TWO_FACTOR = Symbol("twoFactor");
export const BIOMETRIC_LOCK = Symbol("biometricLock");

export type MailPreferences = {
  [key: PropertyKey]: boolean | string;
  doNotDisturb: boolean;
  outOfOffice: boolean;
  [TWO_FACTOR]: boolean;
  [BIOMETRIC_LOCK]: boolean;
};

// don't touch above this line

export function isSecure(preferences: MailPreferences) {
  return false;
}

import { describe, it, assert, withSubmit } from "./unit_test";
import { BIOMETRIC_LOCK, TWO_FACTOR, MailPreferences, isSecure } from "./utils";

describe("isSecure", () => {
  const runCases: {
    preferences: MailPreferences;
    expected: boolean;
  }[] = [
    {
      preferences: {
        doNotDisturb: false,
        outOfOffice: false,
        [BIOMETRIC_LOCK]: true,
        [TWO_FACTOR]: true,
        bloodType: "A+",
        organDonor: true,
      },
      expected: true,
    },
    {
      preferences: {
        doNotDisturb: true,
        outOfOffice: false,
        [BIOMETRIC_LOCK]: true,
        [TWO_FACTOR]: false,
        signature: "Jonathan Harker",
        lawyer: true,
      },
      expected: true,
    },
  ];

  const submitCases = runCases.concat([
    {
      preferences: {
        doNotDisturb: false,
        outOfOffice: true,
        [BIOMETRIC_LOCK]: false,
        [TWO_FACTOR]: true,
        template: "To whom it may concern",
      },
      expected: true,
    },
    {
      preferences: {
        doNotDisturb: true,
