export enum ApiTier {
  Free = "Free",
  Basic = "Basic",
  Pro = "Pro",
  Enterprise = "Enterprise",
}

export function getRateLimitForTier(tier: ApiTier) {
  switch (tier) {
    case ApiTier.Free:
      return 10;
    case ApiTier.Basic:
      return 100;
    case ApiTier.Pro:
      return 1000;
    case ApiTier.Enterprise:
      return 10000;
  }
}

