      const result = getRateLimitForTier(test.tier as any);

      console.log(`Tier:     ${test.tier}`);
      console.log(`Expected Limit: ${test.expected}`);
      console.log(`Actual Limit:   ${result}`);

      assert.strictEqual(result, test.expected);
