}

const assert = {
  strictEqual(actual: any, expected: any, message = "") {
    if (actual !== expected) {
      throw new Error(message || `Expected '${actual}' to equal '${expected}'`);
    }
  },

  greaterThan(actual: any, expected: any, message = "") {
    if (actual <= expected) {
      throw new Error(
        message || `Expected '${actual}' to be greater than '${expected}'`,
      );
    }
  },

  lessThan(actual: any, expected: any, message = "") {
    if (actual >= expected) {
      throw new Error(
        message || `Expected '${actual}' to be less than '${expected}'`,
      );
    }
  },

  deepEqual(actual: any, expected: any, message = "") {
    if (!this._isDeepEqual(actual, expected)) {
      throw new Error(
        message ||
          `Expected
  '${JSON.stringify(actual)}'
to deeply equal:
  '${JSON.stringify(expected)}'`,
      );
    }
  },

  doesNotThrow: function (fn: Function, message?: string): void {
    try {
      fn();
    } catch (error) {
      throw new Error(
        message || `Expected function not to throw, but it did: ${error}`,
      );
    }
  },

  throws: function (
    fn: Function,
    expectedError?: string | Error,
    message?: string,
  ): void {
    try {
      fn();
    } catch (error: unknown) {
      if (!expectedError) {
        return;
      }
      if (typeof error === "object" && error !== null && "message" in error) {
        const err = error as Error;
        if (
          typeof expectedError === "string" &&
          err.message !== expectedError
        ) {
          throw new Error(
            message ||
              `Expected error message to be '${expectedError}', but got '${err.message}'.`,
          );
        }

        if (
          expectedError instanceof Error &&
          err.constructor !== expectedError.constructor
        ) {
          throw new Error(
            message ||
              `Expected error of type '${expectedError.constructor.name}', but got '${err.constructor.name}'.`,
          );
        }
      } else {
        throw new Error(
          message ||
            `Expected an error to be thrown, but received an invalid error.`,
        );
      }
      return;
    }
    throw new Error(message || `Expected function to throw, but it didn't.`);
  },

  _isDeepEqual(obj1: any, obj2: any) {
    if (obj1 === obj2) return true;

    if (
      obj1 === null ||
      typeof obj1 !== "object" ||
      obj2 === null ||
      typeof obj2 !== "object"
    ) {
      return false;
    }

    if (Array.isArray(obj1) && Array.isArray(obj2)) {
      if (obj1.length !== obj2.length) return false;
      for (let i = 0; i < obj1.length; i++) {
        if (!this._isDeepEqual(obj1[i], obj2[i])) return false;
      }
      return true;
    }

    const keys1 = Object.keys(obj1);
    const keys2 = Object.keys(obj2);

    if (keys1.length !== keys2.length) return false;

    for (const key of keys1) {
      if (!keys2.includes(key) || !this._isDeepEqual(obj1[key], obj2[key])) {
        return false;
      }
    }

    return true;
  },
};

